# =========================
# Utilities
# =========================

def now_ms() -> int:
    return int(time.time() * 1000)


def clamp(v: float, lo: float, hi: float) -> float:
    if v < lo:
        return lo
    if v > hi:
        return hi
    return v


def safe_name(s: str) -> str:
    s = (s or "").strip()
    if len(s) > MAX_NAME_LEN:
        s = s[:MAX_NAME_LEN]
    return "".join(ch for ch in s if 32 <= ord(ch) <= 126)


def j_dumps(obj: Any) -> bytes:
    b = json.dumps(obj, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    if ENABLE_ZLIB and len(b) > 256:
        c = zlib.compress(b, ZLIB_LEVEL)
        return b"Z" + c
    return b"J" + b


def j_loads(buf: bytes) -> Any:
    if not buf:
        raise ValueError("empty")
    tag = buf[:1]
    data = buf[1:]
    if tag == b"Z":
        data = zlib.decompress(data)
    elif tag != b"J":
        raise ValueError("bad tag")
    return json.loads(data.decode("utf-8"))


def tcp_pack(payload: bytes) -> bytes:
    return struct.pack("!I", len(payload)) + payload


async def tcp_read_frame(reader: asyncio.StreamReader) -> Optional[bytes]:
    hdr = await reader.readexactly(4)
    (n,) = struct.unpack("!I", hdr)
    if n <= 0 or n > MAX_TCP_FRAME_BYTES:
        raise ValueError("bad frame size")
    return await reader.readexactly(n)


