@dataclass
class PlayerState:
    pid: int
    name: str
    x: float = 0.0
    y: float = 0.0
    z: float = 0.0
    vx: float = 0.0
    vy: float = 0.0
    vz: float = 0.0
    yaw: float = 0.0
    pitch: float = 0.0
    hp: int = 100
    armor: int = 0
    alive: bool = True
    team: int = 0
    weapon: int = 0
    score: int = 0

    last_input_ms: int = field(default_factory=now_ms)
    last_heard_ms: int = field(default_factory=now_ms)
    seq_in: int = 0
    seq_out: int = 0

    # for delta encoding
    last_sent_snapshot: Dict[str, Any] = field(default_factory=dict)

    def to_dict(self) -> Dict[str, Any]:
        return {
            "id": self.pid,
            "n": self.name,
            "p": [self.x, self.y, self.z],
            "v": [self.vx, self.vy, self.vz],
            "r": [self.yaw, self.pitch],
            "hp": self.hp,
            "ar": self.armor,
            "a": 1 if self.alive else 0,
            "t": self.team,
            "w": self.weapon,
            "s": self.score,
        }


@dataclass
class Client:
    addr: Tuple[str, int]
    token: str
    pid: int
    name: str
    udp_last_ms: int = field(default_factory=now_ms)
    tcp_writer: Optional[asyncio.StreamWriter] = None
    tcp_reader: Optional[asyncio.StreamReader] = None
    wants_tcp_state: bool = False
    last_input_ms: int = field(default_factory=now_ms)
    last_input_seq: int = 0
    last_delta_sent_ms: int = 0

    def is_connected_tcp(self) -> bool:
        return self.tcp_writer is not None and not self.tcp_writer.is_closing()


