class BRServer(asyncio.DatagramProtocol):
    def __init__(self):
        self.loop = asyncio.get_event_loop()
        self.transport: Optional[asyncio.DatagramTransport] = None

        self.clients_by_addr: Dict[Tuple[str, int], Client] = {}
        self.clients_by_token: Dict[str, Client] = {}
        self.players: Dict[int, PlayerState] = {}

        self._next_pid = 1

        self._tick_dt = 1.0 / max(1.0, TICK_RATE)
        self._broadcast_dt = 1.0 / max(1.0, STATE_BROADCAST_HZ)
        self._heartbeat_dt = 1.0 / max(0.1, HEARTBEAT_HZ)

        self._running = False
        self._last_broadcast = time.time()
        self._last_heartbeat = time.time()
        self._snapshot_id = 0
        self._last_full_snapshot_id = -1

    # --- UDP Protocol hooks ---
    def connection_made(self, transport):
        self.transport = transport

    def datagram_received(self, data: bytes, addr):
        if len(data) > MAX_PACKET_BYTES:
            return
        try:
            msg = j_loads(data)
            if not isinstance(msg, dict):
                return
        except Exception:
            return
        t = msg.get("t")
        if t == "hello":
            self._handle_hello(msg, addr)
        elif t == "input":
            self._handle_input(msg, addr)
        elif t == "pong":
            self._handle_pong(msg, addr)
        elif t == "bye":
            self._handle_bye(msg, addr)
        else:
            return

    def error_received(self, exc):
        pass

    # --- Client management ---
    def _new_token(self) -> str:
        return os.urandom(16).hex()

    def _alloc_pid(self) -> int:
        pid = self._next_pid
        self._next_pid += 1
        if self._next_pid > 1_000_000_000:
            self._next_pid = 1
        return pid

    def _send_udp(self, addr: Tuple[str, int], obj: Any):
        if not self.transport:
            return
        try:
            payload = j_dumps(obj)
            if len(payload) > MAX_PACKET_BYTES:
                return
            self.transport.sendto(payload, addr)
        except Exception:
            return

    def _kick(self, client: Client, reason: str = "disconnect"):
        addr = client.addr
        token = client.token
        pid = client.pid
        if addr in self.clients_by_addr:
            del self.clients_by_addr[addr]
        if token in self.clients_by_token:
            del self.clients_by_token[token]
        if pid in self.players:
            del self.players[pid]
        if client.is_connected_tcp():
            try:
                client.tcp_writer.close()
            except Exception:
                pass
        self._send_udp(addr, {"t": "kick", "r": reason})

    def _handle_hello(self, msg: Dict[str, Any], addr: Tuple[str, int]):
        if addr in self.clients_by_addr:
            c = self.clients_by_addr[addr]
            c.udp_last_ms = now_ms()
            self._send_udp(addr, {"t": "hello_ack", "id": c.pid, "token": c.token, "server": SERVER_ID})
            return

        if len(self.clients_by_addr) >= MAX_PLAYERS:
            self._send_udp(addr, {"t": "hello_nack", "r": "server_full"})
            return

        name = safe_name(str(msg.get("name", "player")))
        token = self._new_token()
        pid = self._alloc_pid()

        c = Client(addr=addr, token=token, pid=pid, name=name)
        self.clients_by_addr[addr] = c
        self.clients_by_token[token] = c

        ps = PlayerState(pid=pid, name=name)
        ps.x = float(msg.get("x", 0.0))
        ps.y = float(msg.get("y", 0.0))
        ps.z = float(msg.get("z", 0.0))
        ps.x = clamp(ps.x, WORLD_MIN_X, WORLD_MAX_X)
        ps.y = clamp(ps.y, WORLD_MIN_Y, WORLD_MAX_Y)
        ps.z = clamp(ps.z, WORLD_MIN_Z, WORLD_MAX_Z)
        self.players[pid] = ps

        self._send_udp(addr, {
            "t": "hello_ack",
            "id": pid,
            "token": token,
            "server": SERVER_ID,
            "tick": TICK_RATE,
            "state_hz": STATE_BROADCAST_HZ,
            "world": {"min": [WORLD_MIN_X, WORLD_MIN_Y, WORLD_MIN_Z], "max": [WORLD_MAX_X, WORLD_MAX_Y, WORLD_MAX_Z]},
            "tcp_port": TCP_PORT,
        })

        self._broadcast_event({"t": "join", "id": pid, "n": name}, exclude_pid=None)

    def _handle_input(self, msg: Dict[str, Any], addr: Tuple[str, int]):
        c = self.clients_by_addr.get(addr)
        if not c:
            return
        token = msg.get("token")
        if token != c.token:
            return

        tms = now_ms()
        c.udp_last_ms = tms
        c.last_input_ms = tms

        seq = int(msg.get("seq", 0))
        if seq <= c.last_input_seq:
            return

        dt_ms = tms - c.last_input_ms
        _ = dt_ms

        # rate limit (simple)
        if seq - c.last_input_seq > int(MAX_INPUT_RATE_HZ * 2):
            c.last_input_seq = seq - int(MAX_INPUT_RATE_HZ)
        c.last_input_seq = seq

        ps = self.players.get(c.pid)
        if not ps:
            return
        ps.last_heard_ms = tms
        ps.seq_in = seq

        p = msg.get("p")
        if isinstance(p, list) and len(p) >= 3:
            try:
                ps.x = clamp(float(p[0]), WORLD_MIN_X, WORLD_MAX_X)
                ps.y = clamp(float(p[1]), WORLD_MIN_Y, WORLD_MAX_Y)
                ps.z = clamp(float(p[2]), WORLD_MIN_Z, WORLD_MAX_Z)
            except Exception:
                pass

        v = msg.get("v")
        if isinstance(v, list) and len(v) >= 3:
            try:
                ps.vx = float(v[0])
                ps.vy = float(v[1])
                ps.vz = float(v[2])
            except Exception:
                pass

        r = msg.get("r")
        if isinstance(r, list) and len(r) >= 2:
            try:
                ps.yaw = float(r[0])
                ps.pitch = float(r[1])
            except Exception:
                pass

        # optional gameplay fields
        if "hp" in msg:
            try:
                ps.hp = int(msg["hp"])
            except Exception:
                pass
        if "ar" in msg:
            try:
                ps.armor = int(msg["ar"])
            except Exception:
                pass
        if "a" in msg:
            try:
                ps.alive = bool(int(msg["a"]))
            except Exception:
                pass
        if "w" in msg:
            try:
                ps.weapon = int(msg["w"])
            except Exception:
                pass
        if "s" in msg:
            try:
                ps.score = int(msg["s"])
            except Exception:
                pass

    def _handle_pong(self, msg: Dict[str, Any], addr: Tuple[str, int]):
        c = self.clients_by_addr.get(addr)
        if not c:
            return
        if msg.get("token") != c.token:
            return
        c.udp_last_ms = now_ms()

    def _handle_bye(self, msg: Dict[str, Any], addr: Tuple[str, int]):
        c = self.clients_by_addr.get(addr)
        if not c:
            return
        if msg.get("token") != c.token:
            return
        self._kick(c, "bye")

    def _broadcast_event(self, obj: Dict[str, Any], exclude_pid: Optional[int]):
        for c in list(self.clients_by_addr.values()):
            if exclude_pid is not None and c.pid == exclude_pid:
                continue
            self._send_udp(c.addr, obj)

    # --- State snapshots ---
    def _make_full_state(self) -> Dict[str, Any]:
        players = []
        for ps in self.players.values():
            players.append(ps.to_dict())
        return {
            "t": "state",
            "sid": self._snapshot_id,
            "full": 1,
            "ts": now_ms(),
            "players": players,
        }

    def _diff_player(self, ps: PlayerState) -> Dict[str, Any]:
        cur = ps.to_dict()
        prev = ps.last_sent_snapshot
        if not prev:
            return cur
        d: Dict[str, Any] = {"id": ps.pid}
        for k, v in cur.items():
            if k == "id":
                continue
            if prev.get(k) != v:
                d[k] = v
        return d

    def _make_delta_state(self) -> Dict[str, Any]:
        players: List[Dict[str, Any]] = []
        for ps in self.players.values():
            d = self._diff_player(ps)
            if len(d) > 1:
                players.append(d)
        return {
            "t": "state",
            "sid": self._snapshot_id,
            "full": 0,
            "ts": now_ms(),
            "players": players,
        }

    def _commit_sent_snapshot(self):
        for ps in self.players.values():
            ps.last_sent_snapshot = ps.to_dict()

    # --- Main loops ---
    async def run(self):
        self._running = True
        tick_task = self.loop.create_task(self._tick_loop())
        broadcast_task = self.loop.create_task(self._broadcast_loop())
        heartbeat_task = self.loop.create_task(self._heartbeat_loop())
        cleanup_task = self.loop.create_task(self._cleanup_loop())
        await asyncio.gather(tick_task, broadcast_task, heartbeat_task, cleanup_task)

    async def _tick_loop(self):
        while self._running:
            start = time.time()
            self._integrate(self._tick_dt)
            elapsed = time.time() - start
            await asyncio.sleep(max(0.0, self._tick_dt - elapsed))

    def _integrate(self, dt: float):
        # Minimal server-side integration (optional). Clients can be authoritative for positions.
        # Here we just keep within bounds and allow optional velocity integration.
        for ps in self.players.values():
            if not ps.alive:
                continue
            ps.x = clamp(ps.x + ps.vx * dt, WORLD_MIN_X, WORLD_MAX_X)
            ps.y = clamp(ps.y + ps.vy * dt, WORLD_MIN_Y, WORLD_MAX_Y)
            ps.z = clamp(ps.z + ps.vz * dt, WORLD_MIN_Z, WORLD_MAX_Z)

    async def _broadcast_loop(self):
        full_counter = 0
        while self._running:
            t0 = time.time()
            self._snapshot_id += 1
            send_full = False
            full_counter += 1
            if full_counter >= max(1, STATE_FULL_EVERY_N):
                send_full = True
                full_counter = 0

            if send_full or self._last_full_snapshot_id < 0:
                state = self._make_full_state()
                self._last_full_snapshot_id = self._snapshot_id
                for c in list(self.clients_by_addr.values()):
                    self._send_udp(c.addr, state)
                self._commit_sent_snapshot()
            else:
                state = self._make_delta_state()
                for c in list(self.clients_by_addr.values()):
                    if DELTA_MIN_INTERVAL_SEC > 0:
                        nowt = time.time()
                        if nowt - (c.last_delta_sent_ms / 1000.0) < DELTA_MIN_INTERVAL_SEC:
                            continue
                        c.last_delta_sent_ms = now_ms()
                    self._send_udp(c.addr, state)
                # commit after broadcast so deltas are against last sent baseline
                self._commit_sent_snapshot()

            elapsed = time.time() - t0
            await asyncio.sleep(max(0.0, self._broadcast_dt - elapsed))

    async def _heartbeat_loop(self):
        while self._running:
            t0 = time.time()
            ts = now_ms()
            for c in list(self.clients_by_addr.values()):
                self._send_udp(c.addr, {"t": "ping", "ts": ts})
            elapsed = time.time() - t0
            await asyncio.sleep(max(0.0, self._heartbeat_dt - elapsed))

    async def _cleanup_loop(self):
        while self._running:
            await asyncio.sleep(1.0)
            tms = now_ms()
            for c in list(self.clients_by_addr.values()):
                if (tms - c.udp_last_ms) / 1000.0 > CONNECTION_TIMEOUT_SEC:
                    self._kick(c, "timeout")

    # --- TCP for optional full-state streaming / control ---
    async def tcp_handler(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter):
        peer = writer.get_extra_info("peername")
        try:
            first = await tcp_read_frame(reader)
            msg = j_loads(first)
            if not isinstance(msg, dict) or msg.get("t") != "tcp_hello":
                writer.close()
                return
            token = str(msg.get("token", ""))
            c = self.clients_by_token.get(token)
            if not c:
                writer.write(tcp_pack(j_dumps({"t": "tcp_nack", "r": "bad_token"})))
                await writer.drain()
                writer.close()
                return
            c.tcp_reader = reader
            c.tcp_writer = writer
            c.wants_tcp_state = bool(int(msg.get("state", 1)))

            writer.write(tcp_pack(j_dumps({"t": "tcp_ack", "id": c.pid, "server": SERVER_ID})))
            await writer.drain()

            # push an immediate full snapshot
            if c.wants_tcp_state:
                snap = self._make_full_state()
                writer.write(tcp_pack(j_dumps(snap)))
                await writer.drain()

            while not writer.is_closing():
                frame = await tcp_read_frame(reader)
                m = j_loads(frame)
                if not isinstance(m, dict):
                    continue
                if m.get("t") == "tcp_bye":
                    break
                elif m.get("t") == "tcp_state_req":
                    snap = self._make_full_state()
                    writer.write(tcp_pack(j_dumps(snap)))
                    await writer.drain()
                else:
                    continue
        except (asyncio.IncompleteReadError, ConnectionResetError, BrokenPipeError):
            pass
        except Exception:
            pass
        finally:
            try:
                if peer:
                    pass
            except Exception:
                pass
            try:
                writer.close()
            except Exception:
                pass
            # keep UDP session alive; TCP is optional
            for c in list(self.clients_by_addr.values()):
                if c.tcp_writer is writer:
                    c.tcp_writer = None
                    c.tcp_reader = None
                    c.wants_tcp_state = False


# =========================
# Entry
# =========================

async def main():
    loop = asyncio.get_event_loop()
    server = BRServer()

    transport, _ = await loop.create_datagram_endpoint(
        lambda: server,
        local_addr=(HOST, UDP_PORT),
    )
    server.transport = transport

    tcp_srv = await asyncio.start_server(server.tcp_handler, host=HOST, port=TCP_PORT)

    try:
        await server.run()
    finally:
        try:
            transport.close()
        except Exception:
            pass
        try:
            tcp_srv.close()
            await tcp_srv.wait_closed()
        except Exception:
            pass


if __name__ == "__main__":
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        pass